  9→// ---------------------------------------------------------------------------
 10→// Public types
 11→// ---------------------------------------------------------------------------
 12→
 13→/// Actions returned by transcript view key handling.
 14→pub enum TranscriptAction {
 15→    None,
 16→    Back,
 17→    ScrollTo(usize),
 18→}
 19→
 20→/// Persistent state for the fullscreen transcript viewer.
 21→pub struct TranscriptViewState {
 22→    /// Current scroll position (line-based).
 23→    pub scroll_offset: usize,
 24→    /// Indices of expanded tool-call blocks.
 25→    pub expanded_tools: HashSet<usize>,
 26→    /// Whether the right-hand tool-index sidebar is visible.
 27→    pub show_sidebar: bool,
 28→    /// Active search text (set after pressing Enter in search mode).
 29→    pub search_query: Option<String>,
 30→    /// Line indices that match the current search query.
 31→    pub search_matches: Vec<usize>,
 32→    /// Index into `search_matches` for n/N cycling.
 33→    pub search_index: usize,
 34→    /// Whether `/` search-input mode is active.
 35→    pub search_input_active: bool,
 36→    /// Buffer for typing a search query.
 37→    pub search_input_buf: String,
 38→
 39→    // -- Internal bookkeeping (updated each render) --------------------------
 40→    /// Total rendered line count from the last `render()` call.
 41→    total_lines: usize,
 42→    /// Maps tool sequential-index to its rendered-line position.
 43→    tool_line_map: Vec<usize>,
 44→}
 45→
 46→impl Default for TranscriptViewState {
 47→    fn default() -> Self {
 48→        Self::new()
 49→    }
 50→}
 51→
 52→impl TranscriptViewState {
 53→    pub fn new() -> Self {
 54→        Self {
 55→            scroll_offset: 0,
 56→            expanded_tools: HashSet::new(),
 57→            show_sidebar: true,
 58→            search_query: None,
 59→            search_matches: Vec::new(),
 60→            search_index: 0,
 61→            search_input_active: false,
 62→            search_input_buf: String::new(),
 63→            total_lines: 0,
 64→            tool_line_map: Vec::new(),
 65→        }
 66→    }
 67→
 68→    pub fn reset(&mut self) {
 69→        self.scroll_offset = 0;
 70→        self.expanded_tools.clear();
 71→        self.show_sidebar = true;
 72→        self.search_query = None;
 73→        self.search_matches.clear();
 74→        self.search_index = 0;
 75→        self.search_input_active = false;
 76→        self.search_input_buf.clear();
 77→        self.total_lines = 0;
 78→        self.tool_line_map.clear();
 79→    }
 80→}
