 82→// ---------------------------------------------------------------------------
 83→// Rendering
 84→// ---------------------------------------------------------------------------
 85→
 86→/// Render the fullscreen transcript view.
 87→pub fn render(
 88→    frame: &mut Frame,
 89→    area: Rect,
 90→    state: &mut TranscriptViewState,
 91→    entries: &[TranscriptEntry],
 92→) {
 93→    // Build all displayable lines from transcript entries.
 94→    let (lines, tools) = build_lines(entries, state);
 95→    state.total_lines = lines.len();
 96→    state.tool_line_map = tools.iter().map(|t| t.line_index).collect();
 97→
 98→    // Recompute search matches against freshly-built lines.
 99→    if let Some(query) = &state.search_query {
100→        state.search_matches = find_matches(&lines, query);
101→        if !state.search_matches.is_empty() {
102→            state.search_index = state.search_index.min(state.search_matches.len() - 1);
103→        }
104→    }
105→
106→    // Two-panel layout when sidebar is visible.
107→    let (transcript_area, sidebar_area) = if state.show_sidebar {
108→        let chunks = Layout::default()
109→            .direction(Direction::Horizontal)
110→            .constraints([Constraint::Percentage(75), Constraint::Percentage(25)])
111→            .split(area);
112→        (chunks[0], Some(chunks[1]))
113→    } else {
114→        (area, None)
115→    };
116→
117→    // Reserve a bottom row for search bar when relevant.
118→    let show_search_bar = state.search_input_active || state.search_query.is_some();
119→    let (content_area, search_area) = if show_search_bar {
120→        let chunks = Layout::default()
121→            .direction(Direction::Vertical)
122→            .constraints([Constraint::Min(1), Constraint::Length(1)])
123→            .split(transcript_area);
124→        (chunks[0], Some(chunks[1]))
125→    } else {
126→        (transcript_area, None)
127→    };
128→
129→    // The border takes 2 rows (top + bottom).
130→    let inner_height = content_area.height.saturating_sub(2) as usize;
131→
132→    // Handle empty transcript.
133→    if entries.is_empty() {
134→        let block = Block::default().borders(Borders::ALL).title(" Transcript ");
135→        let inner = block.inner(content_area);
136→        frame.render_widget(block, content_area);
137→        let p = Paragraph::new("No transcript data").style(Style::default().fg(Color::DarkGray));
138→        frame.render_widget(p, inner);
139→        if let Some(sa) = sidebar_area {
140→            render_sidebar(frame, sa, &[], state);
141→        }
142→        return;
143→    }
144→
145→    // Clamp scroll offset.
146→    let max_scroll = lines.len().saturating_sub(inner_height);
147→    state.scroll_offset = state.scroll_offset.min(max_scroll);
148→
149→    // Slice visible lines.
150→    let visible: Vec<Line<'_>> = lines
151→        .iter()
152→        .skip(state.scroll_offset)
153→        .take(inner_height)
154→        .cloned()
155→        .collect();
156→
157→    // Apply search highlights to visible slice.
158→    let visible = if state.search_query.is_some() {
159→        apply_search_highlights(
160→            visible,
161→            state.search_query.as_deref().unwrap_or_default(),
162→            &state.search_matches,
163→            state.search_index,
164→            state.scroll_offset,
165→        )
166→    } else {
167→        visible
168→    };
169→
170→    // Scroll position indicator.
171→    let scroll_info = {
172→        let end = (state.scroll_offset + inner_height).min(lines.len());
173→        format!(" {}-{}/{} ", state.scroll_offset + 1, end, lines.len())
174→    };
175→
176→    let transcript_widget = Paragraph::new(Text::from(visible)).block(
177→        Block::default()
178→            .borders(Borders::ALL)
179→            .title(" Transcript ")
180→            .title_bottom(Line::from(scroll_info).right_aligned()),
181→    );
182→    frame.render_widget(transcript_widget, content_area);
183→
184→    // Search bar.
185→    if let Some(search_area) = search_area {
186→        render_search_bar(frame, search_area, state);
187→    }
188→
189→    // Sidebar.
190→    if let Some(sidebar_area) = sidebar_area {
191→        render_sidebar(frame, sidebar_area, &tools, state);
192→    }
193→}
