195→// ---------------------------------------------------------------------------
196→// Key handling
197→// ---------------------------------------------------------------------------
198→
199→/// Handle key events for the transcript view.
200→pub fn handle_key(
201→    key: KeyEvent,
202→    state: &mut TranscriptViewState,
203→    _entry_count: usize,
204→) -> TranscriptAction {
205→    // Search input mode intercepts all keys.
206→    if state.search_input_active {
207→        return handle_search_input(key, state);
208→    }
209→
210→    match key.code {
211→        // -- Scrolling -------------------------------------------------------
212→        KeyCode::Char('j') | KeyCode::Down => {
213→            state.scroll_offset = state.scroll_offset.saturating_add(1);
214→            TranscriptAction::None
215→        }
216→        KeyCode::Char('k') | KeyCode::Up => {
217→            state.scroll_offset = state.scroll_offset.saturating_sub(1);
218→            TranscriptAction::None
219→        }
220→        KeyCode::Char('d') if key.modifiers.contains(KeyModifiers::CONTROL) => {
221→            state.scroll_offset = state.scroll_offset.saturating_add(20);
222→            TranscriptAction::None
223→        }
224→        KeyCode::Char('u') if key.modifiers.contains(KeyModifiers::CONTROL) => {
225→            state.scroll_offset = state.scroll_offset.saturating_sub(20);
226→            TranscriptAction::None
227→        }
228→        KeyCode::Char('g') => {
229→            state.scroll_offset = 0;
230→            TranscriptAction::None
231→        }
232→        KeyCode::Char('G') => {
233→            state.scroll_offset = state.total_lines;
234→            TranscriptAction::None
235→        }
236→
237→        // -- Tool expand / collapse ------------------------------------------
238→        KeyCode::Enter => {
239→            toggle_nearest_tool(state);
240→            TranscriptAction::None
241→        }
242→
243→        // -- Search ----------------------------------------------------------
244→        KeyCode::Char('/') => {
245→            state.search_input_active = true;
246→            state.search_input_buf.clear();
247→            TranscriptAction::None
248→        }
249→        KeyCode::Char('n') => {
250→            advance_match(state, true);
251→            TranscriptAction::None
252→        }
253→        KeyCode::Char('N') => {
254→            advance_match(state, false);
255→            TranscriptAction::None
256→        }
257→
258→        // -- Sidebar ---------------------------------------------------------
259→        KeyCode::Char('o') => {
260→            state.show_sidebar = !state.show_sidebar;
261→            TranscriptAction::None
262→        }
263→
264→        // -- Back / Esc ------------------------------------------------------
265→        KeyCode::Esc => {
266→            if state.search_query.is_some() {
267→                // First Esc clears search; second Esc goes back.
268→                state.search_query = None;
269→                state.search_matches.clear();
270→                state.search_index = 0;
271→                TranscriptAction::None
272→            } else {
273→                TranscriptAction::Back
274→            }
275→        }
276→
277→        _ => TranscriptAction::None,
278→    }
279→}
