285→/// Metadata for a tool-use block tracked during line building.
286→struct ToolEntry {
287→    name: String,
288→    line_index: usize,
289→    tool_index: usize,
290→}
291→
292→/// Convert transcript entries into a flat list of styled lines plus tool
293→/// metadata for the sidebar.
294→fn build_lines(
295→    entries: &[TranscriptEntry],
296→    state: &TranscriptViewState,
297→) -> (Vec<Line<'static>>, Vec<ToolEntry>) {
298→    let mut lines: Vec<Line<'static>> = Vec::new();
299→    let mut tools: Vec<ToolEntry> = Vec::new();
300→    let mut tool_seq: usize = 0;
301→
302→    for entry in entries {
303→        match entry {
304→            TranscriptEntry::Message(msg) => {
305→                append_message(msg, state, &mut lines, &mut tools, &mut tool_seq);
306→            }
307→            TranscriptEntry::FileHistorySnapshot { files } => {
308→                lines.push(Line::from(Span::styled(
309→                    format!("--- file snapshot ({} files) ---", files.len()),
310→                    Style::default().fg(Color::DarkGray),
311→                )));
312→                lines.push(Line::from(""));
313→            }
314→            TranscriptEntry::PrLink {
315→                pr_number, pr_url, ..
316→            } => {
317→                lines.push(Line::from(Span::styled(
318→                    format!("PR #{pr_number}: {pr_url}"),
319→                    Style::default().fg(Color::Cyan),
320→                )));
321→                lines.push(Line::from(""));
322→            }
323→            TranscriptEntry::Progress(raw) => {
324→                let display = truncate(raw, 80);
325→                lines.push(Line::from(Span::styled(
326→                    format!("[progress] {display}"),
327→                    Style::default().fg(Color::DarkGray),
328→                )));
329→            }
330→            TranscriptEntry::Other(_) => {}
331→        }
332→    }
333→
334→    (lines, tools)
335→}
336→
337→fn append_message(
338→    msg: &TranscriptMessage,
339→    state: &TranscriptViewState,
340→    lines: &mut Vec<Line<'static>>,
341→    tools: &mut Vec<ToolEntry>,
342→    tool_seq: &mut usize,
343→) {
344→    // Header line.
345→    let (style, label) = match msg.role {
346→        MessageRole::User => (
347→            Style::default()
348→                .fg(Color::Green)
349→                .add_modifier(Modifier::BOLD),
350→            "[User]",
351→        ),
352→        MessageRole::Assistant => (
353→            Style::default()
354→                .fg(Color::Blue)
355→                .add_modifier(Modifier::BOLD),
356→            "[Assistant]",
357→        ),
358→    };
359→    let ts = msg.timestamp.as_deref().unwrap_or("");
360→    lines.push(Line::from(vec![
361→        Span::styled(format!("{label} "), style),
362→        Span::styled(ts.to_owned(), Style::default().fg(Color::DarkGray)),
363→    ]));
364→
365→    // Content blocks.
366→    for block in &msg.content {
367→        match block {
368→            ContentBlock::Text(text) => {
369→                for l in text.lines() {
370→                    lines.push(Line::from(format!("  {l}")));
371→                }
372→                if text.is_empty() {
373→                    lines.push(Line::from(""));
374→                }
375→            }
376→            ContentBlock::Thinking(text) => {
377→                append_thinking(text, lines);
378→            }
379→            ContentBlock::ToolUse { name, input } => {
380→                append_tool_use(name, input, *tool_seq, state, lines, tools);
381→                *tool_seq += 1;
382→            }
383→            ContentBlock::ToolResult { content, .. } => {
384→                append_tool_result(content, tool_seq.saturating_sub(1), state, lines);
385→            }
386→        }
387→    }
388→
389→    // Blank separator after each message.
390→    lines.push(Line::from(""));
391→}
392→
393→fn append_thinking(text: &str, lines: &mut Vec<Line<'static>>) {
394→    let first = text.lines().next().unwrap_or("");
395→    let multi = text.lines().count() > 1;
396→    let preview = if first.chars().count() > 60 {
397→        format!("{}...", first.chars().take(60).collect::<String>())
398→    } else if multi {
399→        format!("{first}...")
400→    } else {
401→        first.to_owned()
402→    };
403→    lines.push(Line::from(Span::styled(
404→        format!("  [thinking] {preview}"),
405→        Style::default()
406→            .fg(Color::DarkGray)
407→            .add_modifier(Modifier::ITALIC),
408→    )));
409→}
410→
411→fn append_tool_use(
412→    name: &str,
413→    input: &impl std::fmt::Display,
414→    idx: usize,
415→    state: &TranscriptViewState,
416→    lines: &mut Vec<Line<'static>>,
417→    tools: &mut Vec<ToolEntry>,
418→) {
419→    tools.push(ToolEntry {
420→        name: name.to_owned(),
421→        line_index: lines.len(),
422→        tool_index: idx,
423→    });
424→
425→    let expanded = state.expanded_tools.contains(&idx);
426→
427→    if expanded {
428→        // Top border with tool name.
429→        lines.push(Line::from(vec![
430→            Span::styled("  \u{250c}\u{2500} ", Style::default().fg(Color::Yellow)),
431→            Span::styled(
432→                format!("[{idx}] {name}"),
433→                Style::default()
434→                    .fg(Color::Yellow)
435→                    .add_modifier(Modifier::BOLD),
436→            ),
437→        ]));
438→        // Args (compact JSON, split into wrapped chunks).
439→        let raw = input.to_string();
440→        for chunk in wrap_str(&raw, 100) {
441→            lines.push(Line::from(Span::styled(
442→                format!("  \u{2502} {chunk}"),
443→                Style::default().fg(Color::Yellow),
444→            )));
445→        }
446→        // Bottom border.
447→        lines.push(Line::from(Span::styled(
448→            "  \u{2514}\u{2500}".to_owned(),
449→            Style::default().fg(Color::Yellow),
450→        )));
451→    } else {
452→        // Collapsed: single line with tool name and truncated args.
453→        let preview = truncate(&input.to_string(), 60);
454→        lines.push(Line::from(vec![
455→            Span::styled(format!("  [{idx}] "), Style::default().fg(Color::Yellow)),
456→            Span::styled(
457→                name.to_owned(),
458→                Style::default()
459→                    .fg(Color::Yellow)
460→                    .add_modifier(Modifier::BOLD),
461→            ),
462→            Span::styled(format!(" {preview}"), Style::default().fg(Color::DarkGray)),
463→        ]));
464→    }
465→}
466→
467→fn append_tool_result(
468→    content: &str,
469→    parent_idx: usize,
470→    state: &TranscriptViewState,
471→    lines: &mut Vec<Line<'static>>,
472→) {
473→    // Only show result when the parent tool is expanded.
474→    if !state.expanded_tools.contains(&parent_idx) {
475→        return;
476→    }
477→    lines.push(Line::from(Span::styled(
478→        "  Result:".to_owned(),
479→        Style::default()
480→            .fg(Color::DarkGray)
481→            .add_modifier(Modifier::BOLD),
482→    )));
483→    for l in content.lines().take(15) {
484→        lines.push(Line::from(Span::styled(
485→            format!("    {l}"),
486→            Style::default().fg(Color::DarkGray),
487→        )));
488→    }
489→    if content.lines().count() > 15 {
490→        lines.push(Line::from(Span::styled(
491→            "    ...".to_owned(),
492→            Style::default().fg(Color::DarkGray),
493→        )));
494→    }
495→}
