554→// ---------------------------------------------------------------------------
555→// Internal: search helpers
556→// ---------------------------------------------------------------------------
557→
558→fn find_matches(lines: &[Line<'_>], query: &str) -> Vec<usize> {
559→    let q = query.to_ascii_lowercase();
560→    lines
561→        .iter()
562→        .enumerate()
563→        .filter(|(_, line)| {
564→            let text: String = line.spans.iter().map(|s| s.content.as_ref()).collect();
565→            text.to_ascii_lowercase().contains(&q)
566→        })
567→        .map(|(i, _)| i)
568→        .collect()
569→}
570→
571→fn apply_search_highlights<'a>(
572→    lines: Vec<Line<'a>>,
573→    query: &str,
574→    matches: &[usize],
575→    current_idx: usize,
576→    scroll_offset: usize,
577→) -> Vec<Line<'a>> {
578→    let current_line = matches.get(current_idx).copied();
579→    let query_lower = query.to_ascii_lowercase();
580→    let qlen = query.len();
581→
582→    lines
583→        .into_iter()
584→        .enumerate()
585→        .map(|(i, line)| {
586→            let abs = scroll_offset + i;
587→            if !matches.contains(&abs) {
588→                return line;
589→            }
590→            let bg = if current_line == Some(abs) {
591→                Color::Yellow
592→            } else {
593→                Color::DarkGray
594→            };
595→            let new_spans: Vec<Span<'a>> = line
596→                .spans
597→                .into_iter()
598→                .flat_map(|span| highlight_span(span, &query_lower, qlen, bg))
599→                .collect();
600→            Line::from(new_spans)
601→        })
602→        .collect()
603→}
604→
605→fn highlight_span<'a>(span: Span<'a>, query_lower: &str, qlen: usize, bg: Color) -> Vec<Span<'a>> {
606→    let text = span.content.to_string();
607→    let text_lower = text.to_ascii_lowercase();
608→    let positions: Vec<usize> = text_lower
609→        .match_indices(query_lower)
610→        .map(|(pos, _)| pos)
611→        .collect();
612→
613→    if positions.is_empty() {
614→        return vec![span];
615→    }
616→
617→    let base_style = span.style;
618→    let hl_style = base_style.bg(bg).fg(Color::Black);
619→    let mut out = Vec::new();
620→    let mut cursor = 0;
621→
622→    for pos in positions {
623→        if pos > cursor {
624→            out.push(Span::styled(text[cursor..pos].to_owned(), base_style));
625→        }
626→        let end = (pos + qlen).min(text.len());
627→        out.push(Span::styled(text[pos..end].to_owned(), hl_style));
628→        cursor = end;
629→    }
630→    if cursor < text.len() {
631→        out.push(Span::styled(text[cursor..].to_owned(), base_style));
632→    }
633→    out
634→}
635→
636→fn handle_search_input(key: KeyEvent, state: &mut TranscriptViewState) -> TranscriptAction {
637→    match key.code {
638→        KeyCode::Enter => {
639→            if state.search_input_buf.is_empty() {
640→                state.search_query = None;
641→                state.search_matches.clear();
642→            } else {
643→                state.search_query = Some(state.search_input_buf.clone());
644→            }
645→            state.search_input_active = false;
646→            state.search_index = 0;
647→            TranscriptAction::None
648→        }
649→        KeyCode::Esc => {
650→            state.search_input_active = false;
651→            state.search_input_buf.clear();
652→            TranscriptAction::None
653→        }
654→        KeyCode::Backspace => {
655→            state.search_input_buf.pop();
656→            TranscriptAction::None
657→        }
658→        KeyCode::Char(c) => {
659→            state.search_input_buf.push(c);
660→            TranscriptAction::None
661→        }
662→        _ => TranscriptAction::None,
663→    }
664→}
665→
666→fn advance_match(state: &mut TranscriptViewState, forward: bool) {
667→    if state.search_matches.is_empty() {
668→        return;
669→    }
670→    let len = state.search_matches.len();
671→    state.search_index = if forward {
672→        (state.search_index + 1) % len
673→    } else if state.search_index == 0 {
674→        len - 1
675→    } else {
676→        state.search_index - 1
677→    };
678→    if let Some(&line) = state.search_matches.get(state.search_index) {
679→        state.scroll_offset = line;
680→    }
681→}
682→
683→// ---------------------------------------------------------------------------
684→// Internal: tool toggle
685→// ---------------------------------------------------------------------------
686→
687→fn nearest_tool_index(state: &TranscriptViewState) -> Option<usize> {
688→    let scroll = state.scroll_offset;
689→    let mut best: Option<(usize, usize)> = None;
690→    for (idx, &line_pos) in state.tool_line_map.iter().enumerate() {
691→        let dist = scroll.abs_diff(line_pos);
692→        if dist <= 5 && best.is_none_or(|(_, d)| dist < d) {
693→            best = Some((idx, dist));
694→        }
695→    }
696→    best.map(|(idx, _)| idx)
697→}
698→
699→fn toggle_nearest_tool(state: &mut TranscriptViewState) {
700→    if let Some(idx) = nearest_tool_index(state) {
701→        if state.expanded_tools.contains(&idx) {
702→            state.expanded_tools.remove(&idx);
703→        } else {
704→            state.expanded_tools.insert(idx);
705→        }
706→    }
707→}
