 12→/// Which panel has keyboard focus in the detail view.
 13→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 14→pub enum DetailPanel {
 15→    Sessions,
 16→    Files,
 17→    Commits,
 18→    Transcript,
 19→}
 20→
 21→impl DetailPanel {
 22→    fn next(self) -> Self {
 23→        match self {
 24→            Self::Sessions => Self::Files,
 25→            Self::Files => Self::Commits,
 26→            Self::Commits => Self::Transcript,
 27→            Self::Transcript => Self::Sessions,
 28→        }
 29→    }
 30→}
 31→
 32→/// Actions returned by detail view key handling.
 33→pub enum DetailAction {
 34→    None,
 35→    Back,
 36→    OpenTranscript { session_idx: usize },
 37→    OpenDiff { commit_hash: String },
 38→    OpenGitLog,
 39→}
 40→
 41→/// State for the checkpoint detail view.
 42→pub struct DetailState {
 43→    pub focus: DetailPanel,
 44→    pub session_list_state: ListState,
 45→    pub file_list_state: ListState,
 46→    pub commit_list_state: ListState,
 47→    pub transcript_scroll: u16,
 48→}
 49→
 50→impl DetailState {
 51→    pub fn new(session_count: usize) -> Self {
 52→        let mut session_list_state = ListState::default();
 53→        if session_count > 0 {
 54→            session_list_state.select(Some(0));
 55→        }
 56→        Self {
 57→            focus: DetailPanel::Sessions,
 58→            session_list_state,
 59→            file_list_state: ListState::default(),
 60→            commit_list_state: ListState::default(),
 61→            transcript_scroll: 0,
 62→        }
 63→    }
 64→
 65→    pub fn reset(&mut self, session_count: usize) {
 66→        self.focus = DetailPanel::Sessions;
 67→        self.transcript_scroll = 0;
 68→        self.file_list_state = ListState::default();
 69→        self.commit_list_state = ListState::default();
 70→        self.session_list_state = ListState::default();
 71→        if session_count > 0 {
 72→            self.session_list_state.select(Some(0));
 73→        }
 74→    }
 75→}
