 77→/// Render the checkpoint detail view.
 78→///
 79→/// Layout:
 80→/// ```text
 81→/// +--[ checkpoint_id: title ]----------------------------------------+
 82→/// |                    |                                              |
 83→/// | Sessions        3  |  [User]  ...                                |
 84→/// |   Claude Code      |  message text                               |
 85→/// |   ...              |                                              |
 86→/// |                    |  [Assistant]                                 |
 87→/// | Files           5  |  response text                              |
 88→/// |   M schema.sql     |                                              |
 89→/// |   A new_file.rs    |                                              |
 90→/// |                    |                                              |
 91→/// | Commits         2  |                                              |
 92→/// |   c04a441 redesign |                                              |
 93→/// |   727be48 update   |                                              |
 94→/// +--------------------+----------------------------------------------+
 95→/// ```
 96→#[allow(clippy::too_many_lines, clippy::too_many_arguments)]
 97→pub fn render<S: BuildHasher>(
 98→    frame: &mut Frame,
 99→    area: Rect,
100→    state: &mut DetailState,
101→    checkpoint: &CheckpointMeta,
102→    commits: &[CommitInfo],
103→    file_statuses: &HashMap<String, FileStatus, S>,
104→    transcript_entries: Option<&[TranscriptEntry]>,
105→) {
106→    // Header.
107→    let subject = checkpoint
108→        .commit_hashes
109→        .first()
110→        .and_then(|h| commits.iter().find(|c| &c.hash == h || &c.short_hash == h))
111→        .map_or_else(|| checkpoint.checkpoint_id.clone(), |c| c.subject.clone());
112→    let short_id = &checkpoint.checkpoint_id[..checkpoint.checkpoint_id.len().min(12)];
113→    let title = format!(" {short_id}: {subject} ");
114→
115→    let outer_block = Block::default().borders(Borders::ALL).title(title);
116→    let inner_area = outer_block.inner(area);
117→    frame.render_widget(outer_block, area);
118→
119→    // Split into left sidebar (30%) and right transcript (70%).
120→    let h_chunks = Layout::default()
121→        .direction(Direction::Horizontal)
122→        .constraints([Constraint::Percentage(30), Constraint::Percentage(70)])
123→        .split(inner_area);
124→
125→    render_sidebar(
126→        frame,
127→        h_chunks[0],
128→        state,
129→        checkpoint,
130→        commits,
131→        file_statuses,
132→    );
133→    render_transcript_pane(frame, h_chunks[1], state, transcript_entries);
134→}
135→
136→fn render_sidebar<S: BuildHasher>(
137→    frame: &mut Frame,
138→    area: Rect,
139→    state: &mut DetailState,
140→    checkpoint: &CheckpointMeta,
141→    commits: &[CommitInfo],
142→    file_statuses: &HashMap<String, FileStatus, S>,
143→) {
144→    // Split sidebar into 3 sections: Sessions, Files, Commits.
145→    let chunks = Layout::default()
146→        .direction(Direction::Vertical)
147→        .constraints([
148→            Constraint::Percentage(35),
149→            Constraint::Percentage(35),
150→            Constraint::Percentage(30),
151→        ])
152→        .split(area);
153→
154→    // -- Sessions --
155→    let session_items: Vec<ListItem> = checkpoint
156→        .sessions
157→        .iter()
158→        .map(|s| {
159→            let total_tok = s.token_usage.input_tokens + s.token_usage.output_tokens;
160→            let tok_str = format_tokens(total_tok);
161→            let line = format!("  {} — {tok_str}", s.agent);
162→            ListItem::new(Line::from(Span::raw(line)))
163→        })
164→        .collect();
165→
166→    let sessions_title = format!(" Sessions  {} ", checkpoint.sessions.len());
167→    let session_border_style = if state.focus == DetailPanel::Sessions {
168→        Style::default().fg(Color::Yellow)
169→    } else {
170→        Style::default()
171→    };
172→    let session_list = List::new(session_items)
173→        .block(
174→            Block::default()
175→                .borders(Borders::ALL)
176→                .border_style(session_border_style)
177→                .title(sessions_title),
178→        )
179→        .highlight_style(Style::default().bg(Color::DarkGray))
180→        .highlight_symbol("> ");
181→    frame.render_stateful_widget(session_list, chunks[0], &mut state.session_list_state);
182→
183→    // -- Files --
184→    let file_items: Vec<ListItem> = checkpoint
185→        .files_touched
186→        .iter()
187→        .map(|f| {
188→            let badge = match file_statuses.get(f.as_str()) {
189→                Some(FileStatus::Added) => "A",
190→                Some(FileStatus::Modified) | None => "M",
191→                Some(FileStatus::Deleted) => "D",
192→                Some(FileStatus::Renamed) => "R",
193→            };
194→            let line = format!("  {badge} {f}");
195→            ListItem::new(Line::from(Span::raw(line)))
196→        })
197→        .collect();
198→
199→    let files_title = format!(" Files  {} ", checkpoint.files_touched.len());
200→    let file_border_style = if state.focus == DetailPanel::Files {
201→        Style::default().fg(Color::Yellow)
202→    } else {
203→        Style::default()
204→    };
205→    let file_list = List::new(file_items)
206→        .block(
207→            Block::default()
208→                .borders(Borders::ALL)
209→                .border_style(file_border_style)
210→                .title(files_title),
211→        )
212→        .highlight_style(Style::default().bg(Color::DarkGray))
213→        .highlight_symbol("> ");
214→    frame.render_stateful_widget(file_list, chunks[1], &mut state.file_list_state);
215→
216→    // -- Commits --
217→    let relevant_commits: Vec<&CommitInfo> = checkpoint
218→        .commit_hashes
219→        .iter()
220→        .filter_map(|h| commits.iter().find(|c| &c.hash == h || &c.short_hash == h))
221→        .collect();
222→
223→    let commit_items: Vec<ListItem> = relevant_commits
224→        .iter()
225→        .map(|c| {
226→            let line = format!("  {} {}", c.short_hash, truncate(&c.subject, 30));
227→            ListItem::new(Line::from(Span::raw(line)))
228→        })
229→        .collect();
230→
231→    let commits_title = format!(" Commits  {} ", relevant_commits.len());
232→    let commit_border_style = if state.focus == DetailPanel::Commits {
233→        Style::default().fg(Color::Yellow)
234→    } else {
235→        Style::default()
236→    };
237→    let commit_list = List::new(commit_items)
238→        .block(
239→            Block::default()
240→                .borders(Borders::ALL)
241→                .border_style(commit_border_style)
242→                .title(commits_title),
243→        )
244→        .highlight_style(Style::default().bg(Color::DarkGray))
245→        .highlight_symbol("> ");
246→    frame.render_stateful_widget(commit_list, chunks[2], &mut state.commit_list_state);
247→}
