249→fn render_transcript_pane(
250→    frame: &mut Frame,
251→    area: Rect,
252→    state: &DetailState,
253→    transcript_entries: Option<&[TranscriptEntry]>,
254→) {
255→    let border_style = if state.focus == DetailPanel::Transcript {
256→        Style::default().fg(Color::Yellow)
257→    } else {
258→        Style::default()
259→    };
260→    let block = Block::default()
261→        .borders(Borders::ALL)
262→        .border_style(border_style)
263→        .title(" Transcript ");
264→    let inner = block.inner(area);
265→    frame.render_widget(block, area);
266→
267→    let Some(entries) = transcript_entries else {
268→        let loading =
269→            Paragraph::new("Loading transcript...").style(Style::default().fg(Color::DarkGray));
270→        frame.render_widget(loading, inner);
271→        return;
272→    };
273→
274→    if entries.is_empty() {
275→        let empty =
276→            Paragraph::new("No transcript data").style(Style::default().fg(Color::DarkGray));
277→        frame.render_widget(empty, inner);
278→        return;
279→    }
280→
281→    // Render transcript as styled lines.
282→    let mut lines: Vec<Line> = Vec::new();
283→
284→    for entry in entries {
285→        match entry {
286→            TranscriptEntry::Message(msg) => {
287→                render_message_lines(&mut lines, msg);
288→            }
289→            TranscriptEntry::Progress(text) => {
290→                lines.push(Line::from(Span::styled(
291→                    format!("  {text}"),
292→                    Style::default().fg(Color::DarkGray),
293→                )));
294→            }
295→            TranscriptEntry::PrLink {
296→                pr_number, pr_url, ..
297→            } => {
298→                lines.push(Line::from(Span::styled(
299→                    format!("  PR #{pr_number}: {pr_url}"),
300→                    Style::default().fg(Color::Magenta),
301→                )));
302→            }
303→            TranscriptEntry::FileHistorySnapshot { files } => {
304→                lines.push(Line::from(Span::styled(
305→                    format!("  [Snapshot: {} files]", files.len()),
306→                    Style::default().fg(Color::DarkGray),
307→                )));
308→            }
309→            TranscriptEntry::Other(_) => {}
310→        }
311→        lines.push(Line::from(""));
312→    }
313→
314→    let paragraph = Paragraph::new(lines)
315→        .wrap(Wrap { trim: false })
316→        .scroll((state.transcript_scroll, 0));
317→    frame.render_widget(paragraph, inner);
318→}
319→
320→fn render_message_lines(lines: &mut Vec<Line>, msg: &mementor_lib::model::TranscriptMessage) {
321→    // Header line.
322→    let (role_label, role_style) = match msg.role {
323→        MessageRole::User => (
324→            "[User]",
325→            Style::default()
326→                .fg(Color::Green)
327→                .add_modifier(Modifier::BOLD),
328→        ),
329→        MessageRole::Assistant => (
330→            "[Assistant]",
331→            Style::default()
332→                .fg(Color::Blue)
333→                .add_modifier(Modifier::BOLD),
334→        ),
335→    };
336→
337→    let timestamp_str = msg.timestamp.as_deref().unwrap_or("");
338→    lines.push(Line::from(vec![
339→        Span::styled(format!("  {role_label}"), role_style),
340→        Span::styled(
341→            format!("  {timestamp_str}"),
342→            Style::default().fg(Color::DarkGray),
343→        ),
344→    ]));
345→
346→    // Content blocks.
347→    for block in &msg.content {
348→        match block {
349→            ContentBlock::Text(text) => {
350→                for line in text.lines() {
351→                    lines.push(Line::from(Span::raw(format!("  {line}"))));
352→                }
353→            }
354→            ContentBlock::Thinking(text) => {
355→                let preview = truncate(text, 80);
356→                lines.push(Line::from(Span::styled(
357→                    format!("  [thinking] {preview}"),
358→                    Style::default()
359→                        .fg(Color::DarkGray)
360→                        .add_modifier(Modifier::ITALIC),
361→                )));
362→            }
363→            ContentBlock::ToolUse { name, .. } => {
364→                lines.push(Line::from(Span::styled(
365→                    format!("  [{name}]"),
366→                    Style::default().fg(Color::Cyan),
367→                )));
368→            }
369→            ContentBlock::ToolResult { content, .. } => {
370→                let preview = truncate(content, 60);
371→                lines.push(Line::from(Span::styled(
372→                    format!("    → {preview}"),
373→                    Style::default().fg(Color::DarkGray),
374→                )));
375→            }
376→        }
377→    }
378→}
