380→/// Handle key events for the detail view.
381→pub fn handle_key(
382→    key: KeyEvent,
383→    state: &mut DetailState,
384→    checkpoint: &CheckpointMeta,
385→    commits: &[CommitInfo],
386→) -> DetailAction {
387→    match key.code {
388→        KeyCode::Esc => DetailAction::Back,
389→        KeyCode::Tab => {
390→            state.focus = state.focus.next();
391→            DetailAction::None
392→        }
393→        KeyCode::Char('t') => {
394→            let session_idx = state.session_list_state.selected().unwrap_or(0);
395→            DetailAction::OpenTranscript { session_idx }
396→        }
397→        KeyCode::Char('d') => {
398→            let hashes = relevant_commit_hashes(checkpoint, commits);
399→            if let Some(idx) = state.commit_list_state.selected() {
400→                let hash = hashes.get(idx).cloned().unwrap_or_default();
401→                DetailAction::OpenDiff { commit_hash: hash }
402→            } else if let Some(hash) = hashes.first() {
403→                DetailAction::OpenDiff {
404→                    commit_hash: hash.clone(),
405→                }
406→            } else {
407→                DetailAction::None
408→            }
409→        }
410→        KeyCode::Char('g') => DetailAction::OpenGitLog,
411→        KeyCode::Char('j') | KeyCode::Down => {
412→            handle_scroll_down(state, checkpoint, commits);
413→            DetailAction::None
414→        }
415→        KeyCode::Char('k') | KeyCode::Up => {
416→            handle_scroll_up(state, checkpoint, commits);
417→            DetailAction::None
418→        }
419→        KeyCode::Enter => handle_enter(state, checkpoint, commits),
420→        _ => DetailAction::None,
421→    }
422→}
423→
424→fn handle_scroll_down(
425→    state: &mut DetailState,
426→    checkpoint: &CheckpointMeta,
427→    commits: &[CommitInfo],
428→) {
429→    match state.focus {
430→        DetailPanel::Sessions => {
431→            let len = checkpoint.sessions.len();
432→            scroll_list_down(&mut state.session_list_state, len);
433→        }
434→        DetailPanel::Files => {
435→            let len = checkpoint.files_touched.len();
436→            scroll_list_down(&mut state.file_list_state, len);
437→        }
438→        DetailPanel::Commits => {
439→            let relevant = checkpoint
440→                .commit_hashes
441→                .iter()
442→                .filter(|h| commits.iter().any(|c| &c.hash == *h || &c.short_hash == *h))
443→                .count();
444→            scroll_list_down(&mut state.commit_list_state, relevant);
445→        }
446→        DetailPanel::Transcript => {
447→            state.transcript_scroll = state.transcript_scroll.saturating_add(1);
448→        }
449→    }
450→}
451→
452→fn handle_scroll_up(
453→    state: &mut DetailState,
454→    _checkpoint: &CheckpointMeta,
455→    _commits: &[CommitInfo],
456→) {
457→    match state.focus {
458→        DetailPanel::Sessions => scroll_list_up(&mut state.session_list_state),
459→        DetailPanel::Files => scroll_list_up(&mut state.file_list_state),
460→        DetailPanel::Commits => scroll_list_up(&mut state.commit_list_state),
461→        DetailPanel::Transcript => {
462→            state.transcript_scroll = state.transcript_scroll.saturating_sub(1);
463→        }
464→    }
465→}
466→
467→fn handle_enter(
468→    state: &DetailState,
469→    checkpoint: &CheckpointMeta,
470→    commits: &[CommitInfo],
471→) -> DetailAction {
472→    let hashes = relevant_commit_hashes(checkpoint, commits);
473→    match state.focus {
474→        DetailPanel::Commits => {
475→            if let Some(idx) = state.commit_list_state.selected() {
476→                let hash = hashes.get(idx).cloned().unwrap_or_default();
477→                DetailAction::OpenDiff { commit_hash: hash }
478→            } else {
479→                DetailAction::None
480→            }
481→        }
482→        DetailPanel::Files => {
483→            if let Some(hash) = hashes.first() {
484→                DetailAction::OpenDiff {
485→                    commit_hash: hash.clone(),
486→                }
487→            } else {
488→                DetailAction::None
489→            }
490→        }
491→        DetailPanel::Sessions | DetailPanel::Transcript => {
492→            let session_idx = state.session_list_state.selected().unwrap_or(0);
493→            DetailAction::OpenTranscript { session_idx }
494→        }
495→    }
496→}
497→
498→fn scroll_list_down(list_state: &mut ListState, len: usize) {
499→    if len == 0 {
500→        return;
501→    }
502→    let i = list_state
503→        .selected()
504→        .map_or(0, |i| if i + 1 < len { i + 1 } else { i });
505→    list_state.select(Some(i));
506→}
507→
508→fn scroll_list_up(list_state: &mut ListState) {
509→    let i = list_state.selected().map_or(0, |i| i.saturating_sub(1));
510→    list_state.select(Some(i));
511→}
