513→/// Return the commit hashes from the checkpoint that are actually present in
514→/// the `commits` list, in the same order as displayed in the sidebar.
515→fn relevant_commit_hashes(checkpoint: &CheckpointMeta, commits: &[CommitInfo]) -> Vec<String> {
516→    checkpoint
517→        .commit_hashes
518→        .iter()
519→        .filter(|h| commits.iter().any(|c| &c.hash == *h || &c.short_hash == *h))
520→        .cloned()
521→        .collect()
522→}
