528→#[allow(clippy::cast_precision_loss)]
529→fn format_tokens(total: u64) -> String {
530→    if total >= 1_000_000 {
531→        let m = total as f64 / 1_000_000.0;
532→        format!("{m:.1}M tok")
533→    } else if total >= 1_000 {
534→        let k = total as f64 / 1_000.0;
535→        format!("{k:.1}K tok")
536→    } else {
537→        format!("{total} tok")
538→    }
539→}
