 5→/// List local branches, excluding `entire/*` branches.
 6→pub async fn list_branches() -> Result<Vec<String>> {
 7→    let output = git(&["branch", "--format=%(refname:short)"]).await?;
 8→    let branches = output
 9→        .lines()
10→        .filter(|line| !line.is_empty())
11→        .filter(|line| !line.starts_with("entire/"))
12→        .map(String::from)
13→        .collect();
14→    Ok(branches)
15→}
