17→/// Return the name of the currently checked-out branch.
18→pub async fn current_branch() -> Result<String> {
19→    let output = git(&["rev-parse", "--abbrev-ref", "HEAD"]).await?;
20→    Ok(output.trim().to_owned())
21→}
