 12→/// In-memory cache for checkpoint data, commit logs, transcripts, and diffs.
 13→///
 14→/// Checkpoint list and commit log are loaded eagerly on initialization.
 15→/// Transcripts and diffs are loaded lazily on first access.
 16→pub struct DataCache {
 17→    checkpoints: Vec<CheckpointMeta>,
 18→    commits: Vec<CommitInfo>,
 19→    transcripts: HashMap<String, Vec<TranscriptEntry>>,
 20→    diffs: HashMap<String, Vec<FileDiff>>,
 21→    branch: String,
 22→}
 23→
 24→impl DataCache {
 25→    /// Load the checkpoint list and commit log for the given branch.
 26→    pub async fn initialize(branch: &str) -> Result<Self> {
 27→        let mut checkpoints = checkpoint::list_checkpoints().await.unwrap_or_default();
 28→        let commits = log::log_with_checkpoints(branch, 200)
 29→            .await
 30→            .unwrap_or_default();
 31→
 32→        link_commit_hashes(&mut checkpoints, &commits);
 33→
 34→        Ok(Self {
 35→            checkpoints,
 36→            commits,
 37→            transcripts: HashMap::new(),
 38→            diffs: HashMap::new(),
 39→            branch: branch.to_owned(),
 40→        })
 41→    }
 42→
 43→    /// Return the cached checkpoint list.
 44→    pub fn checkpoints(&self) -> &[CheckpointMeta] {
 45→        &self.checkpoints
 46→    }
 47→
 48→    /// Return the cached commit log.
 49→    pub fn commits(&self) -> &[CommitInfo] {
 50→        &self.commits
 51→    }
 52→
 53→    /// Get the transcript for a checkpoint session, loading it lazily from the
 54→    /// git tree if not already cached.
 55→    pub async fn transcript(&mut self, blob_path: &str) -> Result<&[TranscriptEntry]> {
 56→        if !self.transcripts.contains_key(blob_path) {
 57→            let bytes = tree::show_blob("entire/checkpoints/v1", blob_path).await?;
 58→            let entries = transcript::parse_transcript(&bytes)?;
 59→            self.transcripts.insert(blob_path.to_owned(), entries);
 60→        }
 61→
 62→        Ok(self.transcripts.get(blob_path).expect("just inserted"))
 63→    }
 64→
 65→    /// Get the diff for a commit, loading it lazily if not already cached.
 66→    pub async fn diffs(&mut self, commit_hash: &str) -> Result<&[FileDiff]> {
 67→        if !self.diffs.contains_key(commit_hash) {
 68→            let file_diffs = diff::diff_commit(commit_hash).await?;
 69→            self.diffs.insert(commit_hash.to_owned(), file_diffs);
 70→        }
 71→
 72→        Ok(self.diffs.get(commit_hash).expect("just inserted"))
 73→    }
 74→
 75→    /// Return already-cached diffs for a commit, or `None` if not yet loaded.
 76→    ///
 77→    /// Unlike [`Self::diffs`], this is synchronous and will not trigger a load.
 78→    pub fn cached_diffs(&self, commit_hash: &str) -> Option<&[FileDiff]> {
 79→        self.diffs.get(commit_hash).map(Vec::as_slice)
 80→    }
 81→
 82→    /// Refresh the checkpoint list and commit log from git.
 83→    pub async fn refresh(&mut self) -> Result<()> {
 84→        self.checkpoints = checkpoint::list_checkpoints().await.unwrap_or_default();
 85→        self.commits = log::log_with_checkpoints(&self.branch, 200)
 86→            .await
 87→            .unwrap_or_default();
 88→        link_commit_hashes(&mut self.checkpoints, &self.commits);
 89→        Ok(())
 90→    }
 91→}
 92→
 93→/// Cross-reference commits with checkpoints to populate `commit_hashes`.
 94→fn link_commit_hashes(checkpoints: &mut [CheckpointMeta], commits: &[CommitInfo]) {
 95→    for commit in commits {
 96→        if let Some(cp_id) = &commit.checkpoint_id
 97→            && let Some(cp) = checkpoints.iter_mut().find(|c| &c.checkpoint_id == cp_id)
 98→        {
 99→            cp.commit_hashes.push(commit.hash.clone());
100→        }
101→    }
102→}
