  4→use crate::model::{
  5→    ContentBlock, ConversationSegment, MessageRole, TranscriptEntry, TranscriptMessage,
  6→};
  7→
  8→/// Parse a JSONL transcript file into a sequence of transcript entries.
  9→///
 10→/// Each line is expected to be a JSON object with a `"type"` field that
 11→/// determines the entry variant.
 12→pub fn parse_transcript(jsonl: &[u8]) -> Result<Vec<TranscriptEntry>> {
 13→    let text = std::str::from_utf8(jsonl).context("transcript is not valid UTF-8")?;
 14→    let mut entries = Vec::new();
 15→
 16→    for (i, line) in text.lines().enumerate() {
 17→        let line = line.trim();
 18→        if line.is_empty() {
 19→            continue;
 20→        }
 21→
 22→        let value: Value = serde_json::from_str(line)
 23→            .with_context(|| format!("failed to parse JSON at line {}", i + 1))?;
 24→
 25→        entries.push(parse_entry(&value, line));
 26→    }
 27→
 28→    Ok(entries)
 29→}
 30→
 31→/// Group transcript entries into conversation segments.
 32→///
 33→/// Each segment starts with a user message and includes all entries until the
 34→/// next user message. Entries before the first user message form their own
 35→/// segment.
 36→pub fn group_into_segments(entries: &[TranscriptEntry]) -> Vec<ConversationSegment> {
 37→    let mut segments = Vec::new();
 38→    let mut current: Vec<TranscriptEntry> = Vec::new();
 39→
 40→    for entry in entries {
 41→        let is_user = matches!(
 42→            entry,
 43→            TranscriptEntry::Message(msg) if msg.role == MessageRole::User
 44→        );
 45→
 46→        if is_user && !current.is_empty() {
 47→            segments.push(ConversationSegment { entries: current });
 48→            current = Vec::new();
 49→        }
 50→
 51→        current.push(entry.clone());
 52→    }
 53→
 54→    if !current.is_empty() {
 55→        segments.push(ConversationSegment { entries: current });
 56→    }
 57→
 58→    segments
 59→}
