 61→fn parse_entry(value: &Value, raw_line: &str) -> TranscriptEntry {
 62→    let entry_type = value.get("type").and_then(Value::as_str).unwrap_or("");
 63→
 64→    match entry_type {
 65→        "user" => parse_user_message(value),
 66→        "assistant" => parse_assistant_message(value),
 67→        "file-history-snapshot" => parse_file_history_snapshot(value),
 68→        "progress" => TranscriptEntry::Progress(raw_line.to_owned()),
 69→        "pr-link" => parse_pr_link(value),
 70→        _ => TranscriptEntry::Other(raw_line.to_owned()),
 71→    }
 72→}
 73→
 74→fn parse_user_message(value: &Value) -> TranscriptEntry {
 75→    let msg = &value["message"];
 76→    let content_str = msg["content"].as_str().unwrap_or("");
 77→    let uuid = msg["uuid"].as_str().unwrap_or("").to_owned();
 78→    let timestamp = msg["timestamp"].as_str().map(String::from);
 79→
 80→    TranscriptEntry::Message(TranscriptMessage {
 81→        role: MessageRole::User,
 82→        uuid,
 83→        timestamp,
 84→        content: vec![ContentBlock::Text(content_str.to_owned())],
 85→    })
 86→}
 87→
 88→fn parse_assistant_message(value: &Value) -> TranscriptEntry {
 89→    let msg = &value["message"];
 90→    let uuid = msg["uuid"].as_str().unwrap_or("").to_owned();
 91→    let timestamp = msg["timestamp"].as_str().map(String::from);
 92→
 93→    let content_blocks = msg["content"]
 94→        .as_array()
 95→        .map(|arr| arr.iter().filter_map(parse_content_block).collect())
 96→        .unwrap_or_default();
 97→
 98→    TranscriptEntry::Message(TranscriptMessage {
 99→        role: MessageRole::Assistant,
100→        uuid,
101→        timestamp,
102→        content: content_blocks,
103→    })
104→}
105→
106→fn parse_content_block(block: &Value) -> Option<ContentBlock> {
107→    let block_type = block.get("type")?.as_str()?;
108→
109→    match block_type {
110→        "text" => {
111→            let text = block["text"].as_str().unwrap_or("").to_owned();
112→            Some(ContentBlock::Text(text))
113→        }
114→        "thinking" => {
115→            let thinking = block["thinking"].as_str().unwrap_or("").to_owned();
116→            Some(ContentBlock::Thinking(thinking))
117→        }
118→        "tool_use" => {
119→            let name = block["name"].as_str().unwrap_or("").to_owned();
120→            let input = block
121→                .get("input")
122→                .cloned()
123→                .unwrap_or(Value::Object(serde_json::Map::default()));
124→            Some(ContentBlock::ToolUse { name, input })
125→        }
126→        "tool_result" => {
127→            let tool_use_id = block["tool_use_id"].as_str().unwrap_or("").to_owned();
128→            let content = match &block["content"] {
129→                Value::String(s) => s.clone(),
130→                other => other.to_string(),
131→            };
132→            Some(ContentBlock::ToolResult {
133→                tool_use_id,
134→                content,
135→            })
136→        }
137→        _ => None,
138→    }
139→}
140→
141→fn parse_file_history_snapshot(value: &Value) -> TranscriptEntry {
142→    let files = value
143→        .get("snapshot")
144→        .and_then(|s| s.get("trackedFileBackups"))
145→        .and_then(Value::as_object)
146→        .map(|obj| obj.keys().cloned().collect())
147→        .unwrap_or_default();
148→
149→    TranscriptEntry::FileHistorySnapshot { files }
150→}
151→
152→fn parse_pr_link(value: &Value) -> TranscriptEntry {
153→    let msg = &value["message"];
154→    let pr_number = msg["pr_number"].as_u64().unwrap_or(0);
155→    let pr_url = msg["pr_url"].as_str().unwrap_or("").to_owned();
156→    let repository = msg["repository"].as_str().unwrap_or("").to_owned();
157→
158→    TranscriptEntry::PrLink {
159→        pr_number,
160→        pr_url,
161→        repository,
162→    }
163→}
