501→fn render_sidebar(frame: &mut Frame, area: Rect, tools: &[ToolEntry], state: &TranscriptViewState) {
502→    let nearest = nearest_tool_index(state);
503→
504→    let items: Vec<ListItem<'_>> = tools
505→        .iter()
506→        .map(|t| {
507→            let is_current = nearest == Some(t.tool_index);
508→            let is_expanded = state.expanded_tools.contains(&t.tool_index);
509→
510→            let style = if is_current {
511→                Style::default()
512→                    .fg(Color::Yellow)
513→                    .add_modifier(Modifier::BOLD)
514→            } else if is_expanded {
515→                Style::default().fg(Color::Yellow)
516→            } else {
517→                Style::default().fg(Color::DarkGray)
518→            };
519→
520→            let marker = if is_expanded { "\u{25bc}" } else { "\u{25b6}" };
521→            ListItem::new(Line::from(Span::styled(
522→                format!("{marker} [{0}] {1}", t.tool_index, t.name),
523→                style,
524→            )))
525→        })
526→        .collect();
527→
528→    let list = List::new(items).block(Block::default().borders(Borders::ALL).title(" Tools "));
529→    frame.render_widget(list, area);
530→}
