 4→/// Run `entire explain --checkpoint <id> --short --no-pager` and return the
 5→/// output.
 6→pub async fn explain_short(checkpoint_id: &str) -> Result<String> {
 7→    let output = Command::new("entire")
 8→        .args([
 9→            "explain",
10→            "--checkpoint",
11→            checkpoint_id,
12→            "--short",
13→            "--no-pager",
14→        ])
15→        .output()
16→        .await
17→        .context("failed to run entire explain")?;
