  7→const BRANCH: &str = "entire/checkpoints/v1";
  8→
  9→/// List all checkpoints on the `entire/checkpoints/v1` branch.
 10→///
 11→/// Walks the shard/checkpoint directory structure, reads each checkpoint-level
 12→/// `metadata.json`, then resolves sessions by loading each session's own
 13→/// `metadata.json`.
 14→pub async fn list_checkpoints() -> Result<Vec<CheckpointMeta>> {
 15→    let shards = tree::ls_tree(BRANCH, "").await?;
 16→    let mut checkpoints = Vec::new();
 17→
 18→    for shard in &shards {
 19→        let entries = tree::ls_tree(BRANCH, &shard.name).await?;
 20→
 21→        for entry in &entries {
 22→            let metadata_path = format!("{}/{}/metadata.json", shard.name, entry.name);
 23→
 24→            match tree::show_blob_str(BRANCH, &metadata_path).await {
 25→                Ok(json) => match parse_and_resolve(&json).await {
 26→                    Ok(meta) => checkpoints.push(meta),
 27→                    Err(e) => {
 28→                        tracing::warn!(
 29→                            "failed to parse metadata for {}/{}: {e}",
 30→                            shard.name,
 31→                            entry.name,
 32→                        );
 33→                    }
 34→                },
 35→                Err(e) => {
 36→                    tracing::warn!(
 37→                        "failed to read metadata.json for {}/{}: {e}",
 38→                        shard.name,
 39→                        entry.name,
 40→                    );
 41→                }
 42→            }
 43→        }
 44→    }
 45→
 46→    Ok(checkpoints)
 47→}
