 49→/// Load a single checkpoint by its ID.
 50→///
 51→/// Derives the shard directory from the first two characters of the checkpoint
 52→/// ID.
 53→pub async fn load_checkpoint(checkpoint_id: &str) -> Result<CheckpointMeta> {
 54→    let shard = &checkpoint_id[..2];
 55→    let metadata_path = format!("{shard}/{checkpoint_id}/metadata.json");
 56→
 57→    let json = tree::show_blob_str(BRANCH, &metadata_path)
 58→        .await
 59→        .with_context(|| format!("failed to read metadata for checkpoint {checkpoint_id}"))?;
 60→
 61→    parse_and_resolve(&json).await
 62→}
 63→
 64→/// Parse checkpoint-level JSON and resolve session metadata.
 65→async fn parse_and_resolve(json: &str) -> Result<CheckpointMeta> {
 66→    let raw: RawCheckpointMeta =
 67→        serde_json::from_str(json).context("failed to parse checkpoint metadata")?;
 68→
 69→    let sessions = resolve_sessions(&raw.sessions).await;
 70→
 71→    Ok(CheckpointMeta {
 72→        checkpoint_id: raw.checkpoint_id,
 73→        strategy: raw.strategy,
 74→        branch: raw.branch,
 75→        files_touched: raw.files_touched,
 76→        sessions,
 77→        token_usage: raw.token_usage,
 78→        commit_hashes: Vec::new(),
 79→    })
 80→}
 81→
 82→/// Resolve session references by loading each session's own `metadata.json`.
 83→async fn resolve_sessions(refs: &[SessionRef]) -> Vec<SessionMeta> {
 84→    let mut sessions = Vec::with_capacity(refs.len());
 85→
 86→    for (i, session_ref) in refs.iter().enumerate() {
 87→        let metadata_path = session_ref.metadata.trim_start_matches('/');
 88→        let transcript_path = session_ref.transcript.trim_start_matches('/');
 89→
 90→        match tree::show_blob_str(BRANCH, metadata_path).await {
 91→            Ok(json) => match serde_json::from_str::<SessionMeta>(&json) {
 92→                Ok(mut meta) => {
 93→                    transcript_path.clone_into(&mut meta.blob_path);
 94→                    sessions.push(meta);
 95→                }
 96→                Err(e) => {
 97→                    tracing::warn!("failed to parse session {i} metadata: {e}");
 98→                }
 99→            },
100→            Err(e) => {
101→                tracing::warn!("failed to read session {i} metadata at {metadata_path}: {e}");
102→            }
103→        }
104→    }
105→
106→    sessions
107→}
