  7→pub fn render(frame: &mut Frame, area: Rect, app: &mut App) {
  8→    let checkpoints = app.cache.checkpoints();
  9→    let commits = app.cache.commits();
 10→
 11→    let items: Vec<ListItem> = checkpoints
 12→        .iter()
 13→        .map(|cp| {
 14→            // Line 1: first commit subject or checkpoint_id fallback.
 15→            let subject = cp
 16→                .commit_hashes
 17→                .first()
 18→                .and_then(|hash| commits.iter().find(|c| &c.hash == hash || &c.short_hash == hash))
 19→                .map_or_else(
 20→                    || cp.checkpoint_id.clone(),
 21→                    |c| c.subject.clone(),
 22→                );
 23→
 24→            // Line 2: details.
 25→            let short_hash = cp
 26→                .commit_hashes
 27→                .first()
 28→                .and_then(|hash| commits.iter().find(|c| &c.hash == hash || &c.short_hash == hash))
 29→                .map_or_else(String::new, |c| c.short_hash.clone());
 30→
 31→            let date_str = cp
 32→                .sessions
 33→                .first()
 34→                .map_or_else(String::new, |s| format_relative_time(&s.created_at));
 35→
 36→            let agent = cp
 37→                .sessions
 38→                .first()
 39→                .map_or("unknown", |s| &s.agent);
 40→
 41→            let (additions, deletions) = commit_stats(cp, commits);
 42→
 43→            let files_count = cp.files_touched.len();
 44→
 45→            let total_tokens = cp.token_usage.input_tokens + cp.token_usage.output_tokens;
 46→            let token_display = format_tokens(total_tokens);
 47→
 48→            let detail_line = format!(
 49→                "  {short_hash}  {date_str}  {agent}  +{additions}/-{deletions}  {files_count} files  {token_display}",
 50→            );
 51→
 52→            ListItem::new(vec![
 53→                Line::from(Span::raw(subject)),
 54→                Line::from(Span::styled(
 55→                    detail_line,
 56→                    Style::default().fg(Color::DarkGray),
 57→                )),
 58→            ])
 59→        })
 60→        .collect();
 61→
 62→    let title = format!(" Checkpoints [{}] ", app.selected_branch);
 63→    let list = List::new(items)
 64→        .block(Block::default().borders(Borders::ALL).title(title))
 65→        .highlight_style(Style::default().bg(Color::DarkGray))
 66→        .highlight_symbol("> ");
 67→
 68→    frame.render_stateful_widget(list, area, &mut app.list_state);
 69→}
 70→
 71→fn commit_stats(
 72→    cp: &mementor_lib::model::CheckpointMeta,
 73→    commits: &[mementor_lib::git::log::CommitInfo],
 74→) -> (usize, usize) {
 75→    // Sum additions/deletions from commit diffs is not available in CommitInfo.
 76→    // Use files_touched length as a proxy; actual diff stats would require
 77→    // loading diffs which is lazy. For now, show file count only via the
 78→    // checkpoint's commit count as a rough indicator.
 79→    let _ = (cp, commits);
 80→    (0, 0)
 81→}
