 83→#[allow(clippy::cast_precision_loss)]
 84→fn format_tokens(total: u64) -> String {
 85→    if total >= 1_000_000 {
 86→        let m = total as f64 / 1_000_000.0;
 87→        format!("{m:.1}M tok")
 88→    } else if total >= 1_000 {
 89→        let k = total as f64 / 1_000.0;
 90→        format!("{k:.1}K tok")
 91→    } else {
 92→        format!("{total} tok")
 93→    }
 94→}
 95→
 96→fn format_relative_time(iso_str: &str) -> String {
 97→    // Parse ISO 8601 timestamp and compute relative time.
 98→    // Use jiff for parsing, falling back to raw string on failure.
 99→    let Ok(timestamp) = iso_str.parse::<jiff::Timestamp>() else {
100→        return iso_str.to_owned();
101→    };
102→    let now = jiff::Timestamp::now();
103→    let span = timestamp.until(now);
104→    let Ok(span) = span else {
105→        return iso_str.to_owned();
106→    };
107→
108→    let total_seconds = span.get_seconds();
109→    let hours = total_seconds / 3600;
110→    let days = hours / 24;
111→
112→    if days > 0 {
113→        format!("{days}d ago")
114→    } else if hours > 0 {
115→        format!("{hours}h ago")
116→    } else {
117→        let mins = total_seconds / 60;
118→        if mins > 0 {
119→            format!("{mins}m ago")
120→        } else {
121→            "just now".to_owned()
122→        }
123→    }
124→}
