292→/// Convert transcript entries into a flat list of styled lines plus tool
293→/// metadata for the sidebar.
294→fn build_lines(
295→    entries: &[TranscriptEntry],
296→    state: &TranscriptViewState,
297→) -> (Vec<Line<'static>>, Vec<ToolEntry>) {
298→    let mut lines: Vec<Line<'static>> = Vec::new();
299→    let mut tools: Vec<ToolEntry> = Vec::new();
300→    let mut tool_seq: usize = 0;
301→
302→    for entry in entries {
303→        match entry {
304→            TranscriptEntry::Message(msg) => {
305→                append_message(msg, state, &mut lines, &mut tools, &mut tool_seq);
306→            }
307→            TranscriptEntry::FileHistorySnapshot { files } => {
308→                lines.push(Line::from(Span::styled(
309→                    format!("--- file snapshot ({} files) ---", files.len()),
310→                    Style::default().fg(Color::DarkGray),
311→                )));
312→                lines.push(Line::from(""));
313→            }
314→            TranscriptEntry::PrLink {
315→                pr_number, pr_url, ..
316→            } => {
317→                lines.push(Line::from(Span::styled(
318→                    format!("PR #{pr_number}: {pr_url}"),
319→                    Style::default().fg(Color::Cyan),
320→                )));
321→                lines.push(Line::from(""));
322→            }
323→            TranscriptEntry::Progress(raw) => {
324→                let display = truncate(raw, 80);
325→                lines.push(Line::from(Span::styled(
326→                    format!("[progress] {display}"),
327→                    Style::default().fg(Color::DarkGray),
328→                )));
329→            }
330→            TranscriptEntry::Other(_) => {}
331→        }
332→    }
333→
334→    (lines, tools)
335→}
336→
337→fn append_message(
338→    msg: &TranscriptMessage,
339→    state: &TranscriptViewState,
340→    lines: &mut Vec<Line<'static>>,
341→    tools: &mut Vec<ToolEntry>,
342→    tool_seq: &mut usize,
343→) {
344→    // Header line.
345→    let (style, label) = match msg.role {
346→        MessageRole::User => (
347→            Style::default()
348→                .fg(Color::Green)
349→                .add_modifier(Modifier::BOLD),
350→            "[User]",
351→        ),
352→        MessageRole::Assistant => (
353→            Style::default()
354→                .fg(Color::Blue)
355→                .add_modifier(Modifier::BOLD),
356→            "[Assistant]",
357→        ),
358→    };
359→    let ts = msg.timestamp.as_deref().unwrap_or("");
360→    lines.push(Line::from(vec![
361→        Span::styled(format!("{label} "), style),
362→        Span::styled(ts.to_owned(), Style::default().fg(Color::DarkGray)),
363→    ]));
364→
365→    // Content blocks.
366→    for block in &msg.content {
367→        match block {
368→            ContentBlock::Text(text) => {
369→                for l in text.lines() {
370→                    lines.push(Line::from(format!("  {l}")));
371→                }
372→                if text.is_empty() {
373→                    lines.push(Line::from(""));
374→                }
375→            }
376→            ContentBlock::Thinking(text) => {
377→                append_thinking(text, lines);
378→            }
379→            ContentBlock::ToolUse { name, input } => {
380→                append_tool_use(name, input, *tool_seq, state, lines, tools);
381→                *tool_seq += 1;
382→            }
383→            ContentBlock::ToolResult { content, .. } => {
384→                append_tool_result(content, tool_seq.saturating_sub(1), state, lines);
385→            }
386→        }
387→    }
388→
389→    // Blank separator after each message.
390→    lines.push(Line::from(""));
391→}
392→
393→fn append_thinking(text: &str, lines: &mut Vec<Line<'static>>) {
394→    let first = text.lines().next().unwrap_or("");
395→    let multi = text.lines().count() > 1;
396→    let preview = if first.chars().count() > 60 {
397→        format!("{}...", first.chars().take(60).collect::<String>())
398→    } else if multi {
399→        format!("{first}...")
400→    } else {
401→        first.to_owned()
402→    };
403→    lines.push(Line::from(Span::styled(
404→        format!("  [thinking] {preview}"),
405→        Style::default()
406→            .fg(Color::DarkGray)
407→            .add_modifier(Modifier::ITALIC),
408→    )));
409→}
410→
411→fn append_tool_use(
412→    name: &str,
413→    input: &impl std::fmt::Display,
414→    idx: usize,
415→    state: &TranscriptViewState,
416→    lines: &mut Vec<Line<'static>>,
417→    tools: &mut Vec<ToolEntry>,
418→) {
419→    tools.push(ToolEntry {
420→        name: name.to_owned(),
421→        line_index: lines.len(),
422→        tool_index: idx,
423→    });
424→
425→    let expanded = state.expanded_tools.contains(&idx);
426→
427→    if expanded {
428→        // Top border with tool name.
429→        lines.push(Line::from(vec![
430→            Span::styled("  \u{250c}\u{2500} ", Style::default().fg(Color::Yellow)),
431→            Span::styled(
432→                format!("[{idx}] {name}"),
433→                Style::default()
434→                    .fg(Color::Yellow)
435→                    .add_modifier(Modifier::BOLD),
436→            ),
437→        ]));
438→        // Args (compact JSON, split into wrapped chunks).
439→        let raw = input.to_string();
440→        for chunk in wrap_str(&raw, 100) {
441→            lines.push(Line::from(Span::styled(
442→                format!("  \u{2502} {chunk}"),
443→                Style::default().fg(Color::Yellow),
444→            )));
445→        }
446→        // Bottom border.
447→        lines.push(Line::from(Span::styled(
448→            "  \u{2514}\u{2500}".to_owned(),
449→            Style::default().fg(Color::Yellow),
450→        )));
451→    } else {
452→        // Collapsed: single line with tool name and truncated args.
453→        let preview = truncate(&input.to_string(), 60);
454→        lines.push(Line::from(vec![
455→            Span::styled(format!("  [{idx}] "), Style::default().fg(Color::Yellow)),
456→            Span::styled(
457→                name.to_owned(),
458→                Style::default()
459→                    .fg(Color::Yellow)
460→                    .add_modifier(Modifier::BOLD),
461→            ),
462→            Span::styled(format!(" {preview}"), Style::default().fg(Color::DarkGray)),
463→        ]));
464→    }
465→}
466→
467→fn append_tool_result(
468→    content: &str,
469→    parent_idx: usize,
470→    state: &TranscriptViewState,
471→    lines: &mut Vec<Line<'static>>,
472→) {
473→    // Only show result when the parent tool is expanded.
474→    if !state.expanded_tools.contains(&parent_idx) {
475→        return;
476→    }
477→    lines.push(Line::from(Span::styled(
478→        "  Result:".to_owned(),
479→        Style::default()
480→            .fg(Color::DarkGray)
481→            .add_modifier(Modifier::BOLD),
482→    )));
483→    for l in content.lines().take(15) {
484→        lines.push(Line::from(Span::styled(
485→            format!("    {l}"),
486→            Style::default().fg(Color::DarkGray),
487→        )));
488→    }
489→    if content.lines().count() > 15 {
490→        lines.push(Line::from(Span::styled(
491→            "    ...".to_owned(),
492→            Style::default().fg(Color::DarkGray),
493→        )));
494→    }
495→}
496→
497→// ---------------------------------------------------------------------------
498→// Internal: sidebar
499→// ---------------------------------------------------------------------------
500→
501→fn render_sidebar(frame: &mut Frame, area: Rect, tools: &[ToolEntry], state: &TranscriptViewState) {
502→    let nearest = nearest_tool_index(state);
503→
504→    let items: Vec<ListItem<'_>> = tools
505→        .iter()
506→        .map(|t| {
507→            let is_current = nearest == Some(t.tool_index);
508→            let is_expanded = state.expanded_tools.contains(&t.tool_index);
509→
510→            let style = if is_current {
511→                Style::default()
512→                    .fg(Color::Yellow)
513→                    .add_modifier(Modifier::BOLD)
514→            } else if is_expanded {
515→                Style::default().fg(Color::Yellow)
516→            } else {
517→                Style::default().fg(Color::DarkGray)
518→            };
519→
520→            let marker = if is_expanded { "\u{25bc}" } else { "\u{25b6}" };
521→            ListItem::new(Line::from(Span::styled(
522→                format!("{marker} [{0}] {1}", t.tool_index, t.name),
523→                style,
524→            )))
525→        })
526→        .collect();
527→
528→    let list = List::new(items).block(Block::default().borders(Borders::ALL).title(" Tools "));
529→    frame.render_widget(list, area);
530→}
531→
532→// ---------------------------------------------------------------------------
533→// Internal: search bar
534→// ---------------------------------------------------------------------------
535→
536→fn render_search_bar(frame: &mut Frame, area: Rect, state: &TranscriptViewState) {
537→    let text = if state.search_input_active {
538→        format!("/{}", state.search_input_buf)
539→    } else if let Some(q) = &state.search_query {
540→        let info = if state.search_matches.is_empty() {
541→            "no matches".to_owned()
542→        } else {
543→            format!("{}/{}", state.search_index + 1, state.search_matches.len())
544→        };
545→        format!("/{q}  [{info}]")
546→    } else {
547→        String::new()
548→    };
549→
550→    let bar = Paragraph::new(text).style(Style::default().fg(Color::Yellow));
551→    frame.render_widget(bar, area);
552→}
553→
554→// ---------------------------------------------------------------------------
555→// Internal: search helpers
556→// ---------------------------------------------------------------------------
557→
558→fn find_matches(lines: &[Line<'_>], query: &str) -> Vec<usize> {
559→    let q = query.to_ascii_lowercase();
560→    lines
561→        .iter()
562→        .enumerate()
563→        .filter(|(_, line)| {
564→            let text: String = line.spans.iter().map(|s| s.content.as_ref()).collect();
565→            text.to_ascii_lowercase().contains(&q)
566→        })
567→        .map(|(i, _)| i)
568→        .collect()
569→}
570→
571→fn apply_search_highlights<'a>(
572→    lines: Vec<Line<'a>>,
573→    query: &str,
574→    matches: &[usize],
575→    current_idx: usize,
576→    scroll_offset: usize,
577→) -> Vec<Line<'a>> {
578→    let current_line = matches.get(current_idx).copied();
579→    let query_lower = query.to_ascii_lowercase();
580→    let qlen = query.len();
581→
582→    lines
583→        .into_iter()
584→        .enumerate()
585→        .map(|(i, line)| {
586→            let abs = scroll_offset + i;
587→            if !matches.contains(&abs) {
588→                return line;
589→            }
590→            let bg = if current_line == Some(abs) {
591→                Color::Yellow
592→            } else {
593→                Color::DarkGray
594→            };
595→            let new_spans: Vec<Span<'a>> = line
596→                .spans
597→                .into_iter()
598→                .flat_map(|span| highlight_span(span, &query_lower, qlen, bg))
599→                .collect();
600→            Line::from(new_spans)
601→        })
602→        .collect()
603→}
604→
605→fn highlight_span<'a>(span: Span<'a>, query_lower: &str, qlen: usize, bg: Color) -> Vec<Span<'a>> {
606→    let text = span.content.to_string();
607→    let text_lower = text.to_ascii_lowercase();
608→    let positions: Vec<usize> = text_lower
609→        .match_indices(query_lower)
610→        .map(|(pos, _)| pos)
611→        .collect();
612→
613→    if positions.is_empty() {
614→        return vec![span];
615→    }
616→
617→    let base_style = span.style;
618→    let hl_style = base_style.bg(bg).fg(Color::Black);
619→    let mut out = Vec::new();
620→    let mut cursor = 0;
621→
622→    for pos in positions {
623→        if pos > cursor {
624→            out.push(Span::styled(text[cursor..pos].to_owned(), base_style));
625→        }
626→        let end = (pos + qlen).min(text.len());
627→        out.push(Span::styled(text[pos..end].to_owned(), hl_style));
628→        cursor = end;
629→    }
630→    if cursor < text.len() {
631→        out.push(Span::styled(text[cursor..].to_owned(), base_style));
632→    }
633→    out
634→}
635→
636→fn handle_search_input(key: KeyEvent, state: &mut TranscriptViewState) -> TranscriptAction {
637→    match key.code {
638→        KeyCode::Enter => {
639→            if state.search_input_buf.is_empty() {
640→                state.search_query = None;
641→                state.search_matches.clear();
642→            } else {
643→                state.search_query = Some(state.search_input_buf.clone());
644→            }
645→            state.search_input_active = false;
646→            state.search_index = 0;
647→            TranscriptAction::None
648→        }
649→        KeyCode::Esc => {
650→            state.search_input_active = false;
651→            state.search_input_buf.clear();
652→            TranscriptAction::None
653→        }
654→        KeyCode::Backspace => {
655→            state.search_input_buf.pop();
656→            TranscriptAction::None
657→        }
658→        KeyCode::Char(c) => {
659→            state.search_input_buf.push(c);
660→            TranscriptAction::None
661→        }
662→        _ => TranscriptAction::None,
663→    }
664→}
665→
666→fn advance_match(state: &mut TranscriptViewState, forward: bool) {
667→    if state.search_matches.is_empty() {
668→        return;
669→    }
670→    let len = state.search_matches.len();
671→    state.search_index = if forward {
672→        (state.search_index + 1) % len
673→    } else if state.search_index == 0 {
674→        len - 1
675→    } else {
676→        state.search_index - 1
677→    };
678→    if let Some(&line) = state.search_matches.get(state.search_index) {
679→        state.scroll_offset = line;
680→    }
681→}
682→
683→// ---------------------------------------------------------------------------
684→// Internal: tool toggle
685→// ---------------------------------------------------------------------------
686→
687→fn nearest_tool_index(state: &TranscriptViewState) -> Option<usize> {
688→    let scroll = state.scroll_offset;
689→    let mut best: Option<(usize, usize)> = None;
690→    for (idx, &line_pos) in state.tool_line_map.iter().enumerate() {
691→        let dist = scroll.abs_diff(line_pos);
692→        if dist <= 5 && best.is_none_or(|(_, d)| dist < d) {
693→            best = Some((idx, dist));
694→        }
695→    }
696→    best.map(|(idx, _)| idx)
697→}
698→
699→fn toggle_nearest_tool(state: &mut TranscriptViewState) {
700→    if let Some(idx) = nearest_tool_index(state) {
701→        if state.expanded_tools.contains(&idx) {
702→            state.expanded_tools.remove(&idx);
703→        } else {
704→            state.expanded_tools.insert(idx);
705→        }
706→    }
707→}
708→
709→// ---------------------------------------------------------------------------
710→// Internal: text utilities
711→// ---------------------------------------------------------------------------
712→
713→fn truncate(s: &str, max_width: usize) -> String {
714→    super::text_utils::truncate(s, max_width)
715→}
716→
717→fn wrap_str(s: &str, width: usize) -> Vec<String> {
718→    super::text_utils::wrap_str(s, width)
719→}
