270→        frame.render_widget(loading, inner);
271→        return;
272→    };
273→
274→    if entries.is_empty() {
275→        let empty =
276→            Paragraph::new("No transcript data").style(Style::default().fg(Color::DarkGray));
277→        frame.render_widget(empty, inner);
278→        return;
279→    }
280→
281→    // Render transcript as styled lines.
282→    let mut lines: Vec<Line> = Vec::new();
