380→/// Handle key events for the detail view.
381→pub fn handle_key(
382→    key: KeyEvent,
383→    state: &mut DetailState,
384→    checkpoint: &CheckpointMeta,
385→    commits: &[CommitInfo],
386→) -> DetailAction {
387→    match key.code {
388→        KeyCode::Esc => DetailAction::Back,
389→        KeyCode::Tab => {
390→            state.focus = state.focus.next();
391→            DetailAction::None
392→        }
393→        KeyCode::Char('t') => {
394→            let session_idx = state.session_list_state.selected().unwrap_or(0);
395→            DetailAction::OpenTranscript { session_idx }
396→        }
397→        KeyCode::Char('d') => {
398→            let hashes = relevant_commit_hashes(checkpoint, commits);
399→            if let Some(idx) = state.commit_list_state.selected() {
400→                let hash = hashes.get(idx).cloned().unwrap_or_default();
401→                DetailAction::OpenDiff { commit_hash: hash }
402→            } else if let Some(hash) = hashes.first() {
403→                DetailAction::OpenDiff {
404→                    commit_hash: hash.clone(),
405→                }
406→            } else {
407→                DetailAction::None
408→            }
409→        }
410→        KeyCode::Char('g') => DetailAction::OpenGitLog,
411→        KeyCode::Char('j') | KeyCode::Down => {
412→            handle_scroll_down(state, checkpoint, commits);
